import { Stack, Link, Button, TextField, Box, TypoGraphy } from "@mui/material";

const Login = () => {
  return (
    <>
      <Box>
        <Box sx={{width: 300}} margin="auto" mt={15} textAlign="center">
            <Stack spacing={2}>
                <TypoGraphy>Wel</TypoGraphy>
                <Stack spacing={2}>
                    <TextField label="Mail Address" placeholder="Enter your mail address" />
                    <TextField label="Password" placeholder="Enter your password" />
                    <Button>Login</Button>
                </Stack>
                <Link href="/signup">Don't have an account yet?</Link>
            </Stack>
        </Box>
      </Box>
    </>
  );
};

export default Login;
